// OAuthConfig.js
const oauthConfig = {
  authorizationEndpoint: 'https://your-auth-server.com/oauth/authorize',
  clientId: 'your-client-id',
  redirectUri: 'http://localhost:3000/callback',
  scope: 'openid profile email'
};

export default oauthConfig;

// App.js
import React, { useState, useEffect } from 'react';
import { useHistory } from 'react-router-dom';
import oauthConfig from './OAuthConfig';

const App = () => {
  const [accessToken, setAccessToken] = useState(null);
  const history = useHistory();

  useEffect(() => {
    const hashParams = new URLSearchParams(window.location.hash.replace(/^#/, ''));

    if (hashParams.has('access_token')) {
      const token = hashParams.get('access_token');
      setAccessToken(token);

      // Clear the fragment from the URL
      window.history.pushState({}, document.title, '/');
    }
  }, []);

  const handleLogin = () => {
    const authUrl = `${oauthConfig.authorizationEndpoint}?` +
                    `response_type=token&` +
                    `client_id=${encodeURIComponent(oauthConfig.clientId)}&` +
                    `redirect_uri=${encodeURIComponent(oauthConfig.redirectUri)}&` +
                    `scope=${encodeURIComponent(oauthConfig.scope)}`;

    window.location.href = authUrl;
  };

  return (
    <div>
      {accessToken ? (
        <div>
          <h1>Welcome!</h1>
          <p>Your access token: {accessToken}</p>
        </div>
      ) : (
        <button onClick={handleLogin}>Login with OAuth</button>
      )}
    </div>
  );
};

export default App;

